changeSet.sql:
UPDATE e
SET e.graph_id = n.graph_id
    FROM dbo.Edges e
JOIN dbo.Nodes n ON e.source_node_id = n.node_id;

ALTER TABLE dbo.Edges ALTER COLUMN graph_id BIGINT NOT NULL;

INSERT INTO dbo.tables (db_, name, type, author, version, service, description, column_count, created_at)
VALUES ('liquibase_lab', 'edges table', 'ALTER_TABLE', 'cherevko', 2, 'graph_service',
        'Added direct graph_id for query optimization.',
        (SELECT COUNT(*) FROM sys.columns WHERE object_id = OBJECT_ID('edges table')),
        SYSUTCDATETIME());

rollback.sql:
DELETE FROM dbo.tables WHERE name = 'edges table' AND version = 2;

UPDATE dbo.tables
SET column_count = (SELECT COUNT(*) FROM sys.columns WHERE object_id = OBJECT_ID('edges')),
last_update_at = SYSUTCDATETIME()
WHERE name = 'edges' AND version = 1;
